execution_sequence.command:
mkdir -p {{WEBROOT}} && cat > /etc/nginx/conf.d/lucifer.conf << 'NGINXCONF'
server {
    listen {{PORT}};
    server_name {{SERVER_NAME}};
    root {{WEBROOT}};
    index index.html;
    location / {
        try_files $uri $uri/ =404;
    }
    access_log /var/log/nginx/lucifer_access.log;
    error_log  /var/log/nginx/lucifer_error.log;
}
NGINXCONF
